// health check + AI 診斷
const GEMINI_API_KEY = '__GEMINI_API_KEY__';
const endpoints = JSON.parse($input.first().json.endpoints || '[]');
const results = [];
const incidents = [];
const startTime = new Date().toISOString();

for (const ep of endpoints) {
  const t0 = Date.now();
  let status = 0, error = null, body = '';
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: ep.url,
      timeout: 10000,
      returnFullResponse: true
    });
    status = response.statusCode || 200;
    body = typeof response.body === 'string' ? response.body.substring(0, 200) : JSON.stringify(response.body || {}).substring(0, 200);
  } catch (err) {
    error = err.message || String(err);
  }
  const elapsedMs = Date.now() - t0;
  const ok = !error && status >= 200 && status < 400;

  const record = { name: ep.name, url: ep.url, status, elapsedMs, error, ok, checkedAt: startTime };
  results.push(record);
  if (!ok) incidents.push(record);
}

let aiDiag = '';
if (incidents.length > 0) {
  const prompt = '你是 SRE 助手。下面是 API health check 失敗的 incident。請用 3 句話：(1) 最可能根因（DNS / network / 服務掛 / SSL / timeout 等）(2) 立即可做的診斷指令 (3) 嚴重度 P1/P2/P3。繁中。\n\n<incidents>\n' + JSON.stringify(incidents) + '\n</incidents>';
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
      headers: { 'Content-Type': 'application/json', 'x-goog-api-key': GEMINI_API_KEY },
      body: {
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        generationConfig: { temperature: 0.3, maxOutputTokens: 400, thinkingConfig: { thinkingBudget: 0 } }
      },
      json: true,
      timeout: 30000
    });
    aiDiag = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  } catch (err) {}
}

const tsKey = startTime.replace(/[:T]/g, '').slice(0, 14);
const tgMsg = incidents.length === 0
  ? '✅ 所有 ' + endpoints.length + ' 個 endpoint 健康（' + startTime + '）'
  : '🚨 API 監控異常 ' + incidents.length + '/' + endpoints.length + '\n\n' + incidents.map(r => '❌ ' + r.name + '（' + r.url + '）\n   status=' + r.status + ' err=' + (r.error || '-')).join('\n\n') + '\n\n🤖 AI 診斷：\n' + aiDiag;

return [{
  json: {
    summary: { total: endpoints.length, ok: results.length - incidents.length, fail: incidents.length },
    results, incidents, aiDiag, tgMsg,
    incidentPath: incidents.length > 0 ? '/files/shared/ops-incidents/incident-' + tsKey + '.json' : null
  },
  binary: incidents.length > 0 ? {
    data: { data: Buffer.from(JSON.stringify({ results, incidents, aiDiag, startTime }, null, 2)).toString('base64'), mimeType: 'application/json', fileName: 'incident-' + tsKey + '.json' }
  } : undefined
}];
